tests:
def test_plain_text():
    e = Engine()
    assert e.render('Hello world', {}) == 'Hello world'

def test_variable():
    e = Engine()
    assert e.render('Hello {{ name }}!', {'name': 'Alice'}) == 'Hello Alice!'

def test_missing_var_empty():
    e = Engine()
    assert e.render('{{ missing }}', {}) == ''
